-- QwenUILib Bundled Single-File Library
-- Generated by Antigravity Python Bundler

local modules = {}
local cache = {}

local function custom_require(name)
    if cache[name] then
        return cache[name]
    end
    local func = modules[name]
    if not func then
        error("Module not found: " .. tostring(name))
    end
    local result = func()
    cache[name] = result
    return result
end

modules["components/button"] = function()
-- src/components/button.lua
local Theme = custom_require("core/theme")
local Utils = custom_require("core/utils")

return function(Tab, name, callback)
    callback = callback or function() end

    -- Main Button Frame (Glass)
    local Frame = Instance.new("TextButton", Tab.Frame)
    Frame.Size = UDim2.new(1, 0, 0, 38)
    Frame.BackgroundColor3 = Theme.Glass
    Frame.BackgroundTransparency = 0.75
    Frame.Text = ""
    Frame.AutoButtonColor = false
    Frame.ZIndex = 2
    Utils.Corner(Frame, 8)
    Utils.GlassBorder(Frame, 0.8)

    -- Button Label
    local Label = Instance.new("TextLabel", Frame)
    Label.Size = UDim2.new(1, -20, 1, 0)
    Label.Position = UDim2.new(0, 10, 0, 0)
    Label.BackgroundTransparency = 1
    Label.Text = name
    Label.TextColor3 = Theme.Text
    Label.TextSize = 13
    Label.Font = Theme.Font
    Label.ZIndex = 3

    -- Accent glow layer (hidden by default)
    local Glow = Instance.new("Frame", Frame)
    Glow.Size = UDim2.new(1, 0, 1, 0)
    Glow.BackgroundColor3 = Theme.Accent
    Glow.BackgroundTransparency = 1
    Glow.ZIndex = 2
    Utils.Corner(Glow, 8)

    -- Hover Effect
    Frame.MouseEnter:Connect(function()
        Utils.Tween(Frame, 0.2, {BackgroundTransparency = 0.65})
        Utils.Tween(Glow, 0.2, {BackgroundTransparency = 0.85})
        Utils.Tween(Label, 0.2, {TextColor3 = Theme.Text})
    end)

    Frame.MouseLeave:Connect(function()
        Utils.Tween(Frame, 0.2, {BackgroundTransparency = 0.75})
        Utils.Tween(Glow, 0.2, {BackgroundTransparency = 1})
    end)

    -- Press Effect
    Frame.MouseButton1Down:Connect(function()
        Utils.Tween(Frame, 0.1, {Size = UDim2.new(1, -4, 0, 36)})
        Utils.Tween(Glow, 0.1, {BackgroundTransparency = 0.7})
    end)

    Frame.MouseButton1Up:Connect(function()
        Utils.Tween(Frame, 0.15, {Size = UDim2.new(1, 0, 0, 38)})
        Utils.Tween(Glow, 0.15, {BackgroundTransparency = 0.85})
    end)

    -- Click Handler
    Frame.MouseButton1Click:Connect(function()
        task.spawn(callback)
        
        -- Ripple effect
        local Ripple = Instance.new("Frame", Frame)
        Ripple.Size = UDim2.new(0, 0, 0, 38)
        Ripple.Position = UDim2.new(0.5, 0, 0.5, 0)
        Ripple.AnchorPoint = Vector2.new(0.5, 0.5)
        Ripple.BackgroundColor3 = Theme.Accent
        Ripple.BackgroundTransparency = 0.7
        Ripple.ZIndex = 3
        Utils.Corner(Ripple, 8)
        
        Utils.Tween(Ripple, 0.4, {
            Size = UDim2.new(1.2, 0, 1.2, 0),
            BackgroundTransparency = 1
        })
        
        task.delay(0.4, function()
            Ripple:Destroy()
        end)
    end)

    table.insert(Tab.Elements, { Frame = Frame, Name = name })

    return {
        SetText = function(text) Label.Text = text end,
        Frame = Frame
    }
end
end

modules["components/colorpicker"] = function()
-- src/components/colorpicker.lua
local Theme = custom_require("core/theme")
local Utils = custom_require("core/utils")

-- HSV to RGB conversion
local function HSVtoRGB(h, s, v)
    local r, g, b
    local i = math.floor(h * 6)
    local f = h * 6 - i
    local p = v * (1 - s)
    local q = v * (1 - f * s)
    local t = v * (1 - (1 - f) * s)
    
    i = i % 6
    if i == 0 then r, g, b = v, t, p
    elseif i == 1 then r, g, b = q, v, p
    elseif i == 2 then r, g, b = p, v, t
    elseif i == 3 then r, g, b = p, q, v
    elseif i == 4 then r, g, b = t, p, v
    elseif i == 5 then r, g, b = v, p, q
    end
    
    return Color3.new(r, g, b)
end

-- RGB to HSV conversion
local function RGBtoHSV(color)
    local r, g, b = color.R, color.G, color.B
    local maxVal = math.max(r, g, b)
    local minVal = math.min(r, g, b)
    local delta = maxVal - minVal
    
    local h, s, v = 0, 0, maxVal
    
    if maxVal ~= 0 then
        s = delta / maxVal
    end
    
    if delta ~= 0 then
        if maxVal == r then
            h = (g - b) / delta
        elseif maxVal == g then
            h = 2 + (b - r) / delta
        else
            h = 4 + (r - g) / delta
        end
        h = h / 6
        if h < 0 then h = h + 1 end
    end
    
    return h, s, v
end

return function(Tab, name, defaultColor, callback)
    defaultColor = defaultColor or Color3.fromRGB(100, 150, 255)
    callback = callback or function() end
    
    local h, s, v = RGBtoHSV(defaultColor)
    local isOpen = false

    -- Main Frame (Glass)
    local Frame = Instance.new("Frame", Tab.Frame)
    Frame.Size = UDim2.new(1, 0, 0, 38)
    Frame.BackgroundColor3 = Theme.Glass
    Frame.BackgroundTransparency = 0.75
    Frame.BorderSizePixel = 0
    Frame.ClipsDescendants = true
    Frame.ZIndex = 10
    Utils.Corner(Frame, 8)
    Utils.GlassBorder(Frame, 0.8)

    -- Header
    local Header = Instance.new("TextButton", Frame)
    Header.Size = UDim2.new(1, 0, 0, 38)
    Header.BackgroundColor3 = Theme.Glass
    Header.BackgroundTransparency = 1
    Header.Text = ""
    Header.AutoButtonColor = false
    Header.ZIndex = 11
    Utils.Corner(Header, 8)

    -- Label
    local Label = Instance.new("TextLabel", Header)
    Label.Size = UDim2.new(1, -60, 1, 0)
    Label.Position = UDim2.new(0, 14, 0, 0)
    Label.BackgroundTransparency = 1
    Label.Text = name
    Label.TextColor3 = Theme.Text
    Label.TextSize = 13
    Label.Font = Theme.Font
    Label.TextXAlignment = Enum.TextXAlignment.Left
    Label.ZIndex = 12

    -- Color Preview Button
    local Preview = Instance.new("TextButton", Header)
    Preview.Size = UDim2.new(0, 30, 0, 24)
    Preview.Position = UDim2.new(1, -40, 0.5, -12)
    Preview.BackgroundColor3 = defaultColor
    Preview.Text = ""
    Preview.AutoButtonColor = false
    Preview.ZIndex = 12
    Utils.Corner(Preview, 6)
    Utils.GlassBorder(Preview, 0.8)

    -- Picker Container
    local Picker = Instance.new("Frame", Frame)
    Picker.Size = UDim2.new(1, 0, 0, 0)
    Picker.Position = UDim2.new(0, 0, 0, 38)
    Picker.BackgroundColor3 = Theme.GlassLight
    Picker.BackgroundTransparency = 0.85
    Picker.BorderSizePixel = 0
    Picker.ClipsDescendants = true
    Picker.ZIndex = 10
    Utils.Corner(Picker, 8)

    -- Saturation/Value Picker Area
    local SVArea = Instance.new("Frame", Picker)
    SVArea.Size = UDim2.new(1, -20, 0, 120)
    SVArea.Position = UDim2.new(0, 10, 0, 10)
    SVArea.BackgroundColor3 = HSVtoRGB(h, 1, 1)
    SVArea.BorderSizePixel = 0
    SVArea.ZIndex = 11
    Utils.Corner(SVArea, 6)

    -- Saturation Gradient (White to Transparent)
    local SatGrad = Instance.new("UIGradient", SVArea)
    SatGrad.Color = ColorSequence.new({
        ColorSequenceKeypoint.new(0, Color3.fromRGB(255, 255, 255)),
        ColorSequenceKeypoint.new(1, Color3.fromRGB(255, 255, 255))
    })
    SatGrad.Transparency = NumberSequence.new({
        NumberSequenceKeypoint.new(0, 0),
        NumberSequenceKeypoint.new(1, 1)
    })

    -- Value Gradient (Black to Transparent)
    local ValGrad = Instance.new("UIGradient", SVArea)
    ValGrad.Rotation = 90
    ValGrad.Color = ColorSequence.new({
        ColorSequenceKeypoint.new(0, Color3.fromRGB(0, 0, 0)),
        ColorSequenceKeypoint.new(1, Color3.fromRGB(0, 0, 0))
    })
    ValGrad.Transparency = NumberSequence.new({
        NumberSequenceKeypoint.new(0, 1),
        NumberSequenceKeypoint.new(1, 0)
    })

    -- SV Cursor
    local SVCursor = Instance.new("Frame", SVArea)
    SVCursor.Size = UDim2.new(0, 8, 0, 8)
    SVCursor.BackgroundColor3 = Color3.fromRGB(255, 255, 255)
    SVCursor.BorderSizePixel = 0
    SVCursor.ZIndex = 12
    Utils.Corner(SVCursor, 4)
    local SVCursorStroke = Instance.new("UIStroke", SVCursor)
    SVCursorStroke.Color = Color3.fromRGB(0, 0, 0)
    SVCursorStroke.Thickness = 1

    -- Hue Slider
    local HueSlider = Instance.new("Frame", Picker)
    HueSlider.Size = UDim2.new(1, -20, 0, 12)
    HueSlider.Position = UDim2.new(0, 10, 0, 140)
    HueSlider.BorderSizePixel = 0
    HueSlider.ZIndex = 11
    Utils.Corner(HueSlider, 6)

    -- Hue Gradient (Rainbow)
    local HueGrad = Instance.new("UIGradient", HueSlider)
    HueGrad.Color = ColorSequence.new({
        ColorSequenceKeypoint.new(0, Color3.fromRGB(255, 0, 0)),
        ColorSequenceKeypoint.new(0.17, Color3.fromRGB(255, 255, 0)),
        ColorSequenceKeypoint.new(0.33, Color3.fromRGB(0, 255, 0)),
        ColorSequenceKeypoint.new(0.5, Color3.fromRGB(0, 255, 255)),
        ColorSequenceKeypoint.new(0.67, Color3.fromRGB(0, 0, 255)),
        ColorSequenceKeypoint.new(0.83, Color3.fromRGB(255, 0, 255)),
        ColorSequenceKeypoint.new(1, Color3.fromRGB(255, 0, 0))
    })

    -- Hue Cursor
    local HueCursor = Instance.new("Frame", HueSlider)
    HueCursor.Size = UDim2.new(0, 4, 1, 0)
    HueCursor.BackgroundColor3 = Color3.fromRGB(255, 255, 255)
    HueCursor.BorderSizePixel = 0
    HueCursor.ZIndex = 12
    Utils.Corner(HueCursor, 2)
    local HueCursorStroke = Instance.new("UIStroke", HueCursor)
    HueCursorStroke.Color = Color3.fromRGB(0, 0, 0)
    HueCursorStroke.Thickness = 1

    -- Update Function
    local function UpdateColor()
        local color = HSVtoRGB(h, s, v)
        Preview.BackgroundColor3 = color
        SVArea.BackgroundColor3 = HSVtoRGB(h, 1, 1)
        SVCursor.Position = UDim2.new(s, -4, 1 - v, -4)
        HueCursor.Position = UDim2.new(h, -2, 0, 0)
        task.spawn(callback, color)
    end

    -- SV Dragging
    local svDragging = false
    local svDragConn, svEndConn
    
    SVArea.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
            svDragging = true
            
            local function updateSV(pos)
                local sizeX = SVArea.AbsoluteSize.X
                local sizeY = SVArea.AbsoluteSize.Y
                if sizeX <= 0 or sizeY <= 0 then return end
                
                local relX = math.clamp(pos.X - SVArea.AbsolutePosition.X, 0, sizeX)
                local relY = math.clamp(pos.Y - SVArea.AbsolutePosition.Y, 0, sizeY)
                s = relX / sizeX
                v = 1 - (relY / sizeY)
                UpdateColor()
            end
            
            updateSV(input.Position)
            
            svDragConn = UIS.InputChanged:Connect(function(moveInput)
                if moveInput.UserInputType == Enum.UserInputType.MouseMovement or moveInput.UserInputType == Enum.UserInputType.Touch then
                    updateSV(moveInput.Position)
                end
            end)
            
            svEndConn = UIS.InputEnded:Connect(function(endInput)
                if endInput.UserInputType == Enum.UserInputType.MouseButton1 or endInput.UserInputType == Enum.UserInputType.Touch then
                    svDragging = false
                    if svDragConn then svDragConn:Disconnect() svDragConn = nil end
                    if svEndConn then svEndConn:Disconnect() svEndConn = nil end
                end
            end)
        end
    end)

    -- Hue Dragging
    local hueDragging = false
    local hueDragConn, hueEndConn
    
    HueSlider.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
            hueDragging = true
            
            local function updateHue(pos)
                local sizeX = HueSlider.AbsoluteSize.X
                if sizeX <= 0 then return end
                
                local relX = math.clamp(pos.X - HueSlider.AbsolutePosition.X, 0, sizeX)
                h = relX / sizeX
                UpdateColor()
            end
            
            updateHue(input.Position)
            
            hueDragConn = UIS.InputChanged:Connect(function(moveInput)
                if moveInput.UserInputType == Enum.UserInputType.MouseMovement or moveInput.UserInputType == Enum.UserInputType.Touch then
                    updateHue(moveInput.Position)
                end
            end)
            
            hueEndConn = UIS.InputEnded:Connect(function(endInput)
                if endInput.UserInputType == Enum.UserInputType.MouseButton1 or endInput.UserInputType == Enum.UserInputType.Touch then
                    hueDragging = false
                    if hueDragConn then hueDragConn:Disconnect() hueDragConn = nil end
                    if hueEndConn then hueEndConn:Disconnect() hueEndConn = nil end
                end
            end)
        end
    end)

    -- Toggle Picker
    Header.MouseButton1Click:Connect(function()
        isOpen = not isOpen
        if isOpen then
            Utils.Tween(Frame, 0.25, {Size = UDim2.new(1, 0, 0, 200)})
            Utils.Tween(Picker, 0.25, {Size = UDim2.new(1, 0, 0, 162)})
        else
            Utils.Tween(Picker, 0.25, {Size = UDim2.new(1, 0, 0, 0)})
            Utils.Tween(Frame, 0.25, {Size = UDim2.new(1, 0, 0, 38)})
        end
    end)

    -- Initialize position
    UpdateColor()

    table.insert(Tab.Elements, { Frame = Frame, Name = name })

    return {
        Set = function(color)
            h, s, v = RGBtoHSV(color)
            UpdateColor()
        end,
        Get = function() return HSVtoRGB(h, s, v) end
    }
end
end

modules["components/console"] = function()
-- src/components/console.lua
local Theme = custom_require("core/theme")
local Utils = custom_require("core/utils")

return function(Tab, name)
    local logs = {}
    local logObjects = {}
    
    -- Main Container (Glass)
    local Frame = Instance.new("Frame", Tab.Frame)
    Frame.Size = UDim2.new(1, 0, 0, 180)
    Frame.BackgroundColor3 = Color3.fromRGB(5, 5, 8)
    Frame.BackgroundTransparency = 0.5
    Frame.BorderSizePixel = 0
    Frame.ZIndex = 2
    Utils.Corner(Frame, 8)
    Utils.GlassBorder(Frame, 0.8)

    -- Header Panel
    local Header = Instance.new("Frame", Frame)
    Header.Size = UDim2.new(1, 0, 0, 28)
    Header.BackgroundColor3 = Theme.GlassLight
    Header.BackgroundTransparency = 0.7
    Header.BorderSizePixel = 0
    Header.ZIndex = 3
    Utils.Corner(Header, 8)
    
    -- Cut off bottom corners of header
    local HeaderCut = Instance.new("Frame", Header)
    HeaderCut.Size = UDim2.new(1, 0, 0, 4)
    HeaderCut.Position = UDim2.new(0, 0, 1, -4)
    HeaderCut.BackgroundColor3 = Theme.GlassLight
    HeaderCut.BackgroundTransparency = 0.7
    HeaderCut.BorderSizePixel = 0
    HeaderCut.ZIndex = 3

    local Title = Instance.new("TextLabel", Header)
    Title.Size = UDim2.new(0.3, 0, 1, 0)
    Title.Position = UDim2.new(0, 10, 0, 0)
    Title.BackgroundTransparency = 1
    Title.Text = name or "Console"
    Title.TextColor3 = Theme.Text
    Title.TextSize = 11
    Title.Font = Theme.FontBold
    Title.TextXAlignment = Enum.TextXAlignment.Left
    Title.ZIndex = 4

    -- Console Action Buttons (Clear, Copy)
    local ClearBtn = Instance.new("TextButton", Header)
    ClearBtn.Size = UDim2.new(0, 48, 0, 18)
    ClearBtn.Position = UDim2.new(1, -120, 0.5, -9)
    ClearBtn.BackgroundColor3 = Theme.Glass
    ClearBtn.BackgroundTransparency = 0.6
    ClearBtn.Text = "Clear"
    ClearBtn.TextColor3 = Theme.SubText
    ClearBtn.TextSize = 10
    ClearBtn.Font = Theme.Font
    ClearBtn.AutoButtonColor = false
    ClearBtn.ZIndex = 4
    Utils.Corner(ClearBtn, 4)
    Utils.GlassBorder(ClearBtn, 0.5)

    local CopyBtn = Instance.new("TextButton", Header)
    CopyBtn.Size = UDim2.new(0, 48, 0, 18)
    CopyBtn.Position = UDim2.new(1, -64, 0.5, -9)
    CopyBtn.BackgroundColor3 = Theme.Glass
    CopyBtn.BackgroundTransparency = 0.6
    CopyBtn.Text = "Copy"
    CopyBtn.TextColor3 = Theme.SubText
    CopyBtn.TextSize = 10
    CopyBtn.Font = Theme.Font
    CopyBtn.AutoButtonColor = false
    CopyBtn.ZIndex = 4
    Utils.Corner(CopyBtn, 4)
    Utils.GlassBorder(CopyBtn, 0.5)

    -- Mini search box in console header
    local SearchBox = Instance.new("TextBox", Header)
    SearchBox.Size = UDim2.new(0, 100, 0, 18)
    SearchBox.Position = UDim2.new(1, -230, 0.5, -9)
    SearchBox.BackgroundColor3 = Theme.Glass
    SearchBox.BackgroundTransparency = 0.6
    SearchBox.PlaceholderText = "Filter logs..."
    SearchBox.PlaceholderColor3 = Theme.Muted
    SearchBox.TextColor3 = Theme.Text
    SearchBox.TextSize = 10
    SearchBox.Font = Theme.Font
    SearchBox.Text = ""
    SearchBox.ClearTextOnFocus = false
    SearchBox.ZIndex = 4
    Utils.Corner(SearchBox, 4)
    Utils.GlassBorder(SearchBox, 0.5)

    -- Scrollable Log Viewport
    local LogScroll = Instance.new("ScrollingFrame", Frame)
    LogScroll.Size = UDim2.new(1, -12, 1, -38)
    LogScroll.Position = UDim2.new(0, 6, 0, 32)
    LogScroll.BackgroundTransparency = 1
    LogScroll.ZIndex = 3
    Utils.StyleScroll(LogScroll)

    local Layout = Instance.new("UIListLayout", LogScroll)
    Layout.Padding = UDim.new(0, 2)
    Layout.SortOrder = Enum.SortOrder.LayoutOrder

    local Pad = Instance.new("UIPadding", LogScroll)
    Pad.PaddingLeft = UDim.new(0, 6)
    Pad.PaddingRight = UDim.new(0, 6)
    Pad.PaddingTop = UDim.new(0, 4)

    Layout:GetPropertyChangedSignal("AbsoluteContentSize"):Connect(function()
        LogScroll.CanvasSize = UDim2.new(0, 0, 0, Layout.AbsoluteContentSize.Y + 10)
    end)

    local function ApplyFilter()
        local query = SearchBox.Text:lower()
        for idx, line in ipairs(logs) do
            local obj = logObjects[idx]
            if obj then
                local matches = (query == "") or line.Text:lower():find(query, 1, true)
                obj.Visible = matches
            end
        end
    end

    SearchBox:GetPropertyChangedSignal("Text"):Connect(ApplyFilter)

    local function Log(text, logType)
        logType = logType or "info"
        local timeStr = os.date("%H:%M:%S")
        local fullText = string.format("[%s] %s", timeStr, text)
        
        local color = Theme.Text
        if logType == "warn" then
            color = Color3.fromRGB(255, 180, 50)
        elseif logType == "error" then
            color = Color3.fromRGB(255, 80, 80)
        elseif logType == "success" then
            color = Color3.fromRGB(80, 255, 80)
        elseif logType == "info" then
            color = Theme.Accent
        end

        local logData = { Text = fullText, Color = color, Raw = text }
        table.insert(logs, logData)

        local LineLabel = Instance.new("TextLabel", LogScroll)
        LineLabel.Size = UDim2.new(1, 0, 0, 16)
        LineLabel.BackgroundTransparency = 1
        LineLabel.Text = fullText
        LineLabel.TextColor3 = color
        LineLabel.TextSize = 10
        LineLabel.Font = Enum.Font.Code
        LineLabel.TextXAlignment = Enum.TextXAlignment.Left
        LineLabel.TextWrapped = true
        LineLabel.AutomaticSize = Enum.AutomaticSize.Y
        LineLabel.ZIndex = 4
        
        table.insert(logObjects, LineLabel)
        ApplyFilter()

        -- Auto scroll to bottom
        task.defer(function()
            LogScroll.CanvasPosition = Vector2.new(0, LogScroll.CanvasSize.Y.Offset)
        end)
    end

    local function Clear()
        for _, obj in ipairs(logObjects) do
            obj:Destroy()
        end
        table.clear(logs)
        table.clear(logObjects)
    end

    ClearBtn.MouseButton1Click:Connect(Clear)

    CopyBtn.MouseButton1Click:Connect(function()
        local fullOutput = {}
        for _, log in ipairs(logs) do
            table.insert(fullOutput, log.Text)
        end
        local outputText = table.concat(fullOutput, "\n")
        
        if setclipboard then
            setclipboard(outputText)
            -- Show visual copy success
            CopyBtn.Text = "Copied!"
            task.delay(1.5, function() CopyBtn.Text = "Copy" end)
        else
            -- Notification fallback
            local ScreenGui = Tab.Frame:FindFirstAncestorOfClass("ScreenGui")
            if ScreenGui then
                Utils.Tween(CopyBtn, 0.1, {TextColor3 = Color3.fromRGB(255, 80, 80)})
                task.delay(1.5, function() CopyBtn.TextColor3 = Theme.SubText end)
            end
        end
    end)

    -- Hover animations for action buttons
    Utils.HoverEffect(ClearBtn, Theme.GlassLight, Theme.Glass)
    Utils.HoverEffect(CopyBtn, Theme.GlassLight, Theme.Glass)

    table.insert(Tab.Elements, { Frame = Frame, Name = name })

    return {
        Log = Log,
        Clear = Clear,
        Frame = Frame
    }
end

end

modules["components/dropdown"] = function()
-- src/components/dropdown.lua
