    local SearchBox = Instance.new("TextBox", Menu)
    SearchBox.Size = UDim2.new(1, -20, 0, 24)
    SearchBox.Position = UDim2.new(0, 10, 0, 4)
    SearchBox.BackgroundColor3 = Theme.GlassLight
    SearchBox.BackgroundTransparency = 0.7
    SearchBox.PlaceholderText = "Search options..."
    SearchBox.PlaceholderColor3 = Theme.Muted
    SearchBox.TextColor3 = Theme.Text
    SearchBox.TextSize = 11
    SearchBox.Font = Theme.Font
    SearchBox.Text = ""
    SearchBox.ClearTextOnFocus = false
    SearchBox.ZIndex = 22
    Utils.Corner(SearchBox, 4)
    Utils.GlassBorder(SearchBox, 0.6)

    -- Options Scrolling List
    local Scroll = Instance.new("ScrollingFrame", Menu)
    Scroll.Size = UDim2.new(1, -12, 0, 110)
    Scroll.Position = UDim2.new(0, 6, 0, 34)
    Scroll.BackgroundTransparency = 1
    Scroll.ZIndex = 21
    Utils.StyleScroll(Scroll)

    local Layout = Instance.new("UIListLayout", Scroll)
    Layout.Padding = UDim.new(0, 4)
    Layout.SortOrder = Enum.SortOrder.LayoutOrder

    local Pad = Instance.new("UIPadding", Scroll)
    Pad.PaddingLeft = UDim.new(0, 4)
    Pad.PaddingRight = UDim.new(0, 4)
    Pad.PaddingTop = UDim.new(0, 4)

    Layout:GetPropertyChangedSignal("AbsoluteContentSize"):Connect(function()
        Scroll.CanvasSize = UDim2.new(0, 0, 0, Layout.AbsoluteContentSize.Y + 10)
    end)

    -- Redraw Option Buttons
    local function RenderOptions()
        -- Clear old buttons
        for _, btn in ipairs(optionButtons) do
            btn:Destroy()
        end
        table.clear(optionButtons)

        local query = SearchBox.Text:lower()
        for idx, option in ipairs(options) do
            if query == "" or tostring(option):lower():find(query, 1, true) then
                local OptBtn = Instance.new("TextButton", Scroll)
                OptBtn.Size = UDim2.new(1, 0, 0, 24)
                OptBtn.BackgroundColor3 = (selected == option) and Theme.Accent or Theme.GlassLight
                OptBtn.BackgroundTransparency = (selected == option) and 0.4 or 0.8
                OptBtn.Text = tostring(option)
                OptBtn.TextColor3 = (selected == option) and Theme.Text or Theme.SubText
                OptBtn.TextSize = 12
                OptBtn.Font = (selected == option) and Theme.FontBold or Theme.Font
                OptBtn.AutoButtonColor = false
                OptBtn.ZIndex = 23
                Utils.Corner(OptBtn, 4)
                Utils.GlassBorder(OptBtn, 0.5)

                -- Hover Effect
                OptBtn.MouseEnter:Connect(function()
                    if selected ~= option then
                        Utils.Tween(OptBtn, 0.15, {BackgroundTransparency = 0.6, TextColor3 = Theme.Text})
                    end
                end)
                OptBtn.MouseLeave:Connect(function()
                    if selected ~= option then
                        Utils.Tween(OptBtn, 0.15, {BackgroundTransparency = 0.8, TextColor3 = Theme.SubText})
                    end
                end)

                -- Select Effect
                OptBtn.MouseButton1Click:Connect(function()
                    selected = option
                    ValueText.Text = tostring(option)
                    
                    -- Close dropdown
                    isOpen = false
                    Utils.Tween(Frame, 0.25, {Size = UDim2.new(1, 0, 0, 38)})
                    Utils.Tween(Arrow, 0.25, {Rotation = 0})
                    
                    task.spawn(callback, option)
                    RenderOptions()
                end)

                table.insert(optionButtons, OptBtn)
            end
        end
    end

    -- Toggle Dropdown Menu
    Header.MouseButton1Click:Connect(function()
        isOpen = not isOpen
        if isOpen then
            SearchBox.Text = ""
            RenderOptions()
            Utils.Tween(Frame, 0.25, {Size = UDim2.new(1, 0, 0, 192)})
            Utils.Tween(Arrow, 0.25, {Rotation = 180})
        else
            Utils.Tween(Frame, 0.25, {Size = UDim2.new(1, 0, 0, 38)})
            Utils.Tween(Arrow, 0.25, {Rotation = 0})
        end
    end)

    -- Dynamic Search filter connection
    SearchBox:GetPropertyChangedSignal("Text"):Connect(RenderOptions)

    -- Set Default value
    RenderOptions()

    table.insert(Tab.Elements, { Frame = Frame, Name = name })

    return {
        Set = function(v)
            selected = v
            ValueText.Text = tostring(v)
            RenderOptions()
            task.spawn(callback, v)
        end,
        Get = function() return selected end,
        Refresh = function(newOptions)
            options = newOptions or {}
            if not table.find(options, selected) then
                selected = options[1] or ""
                ValueText.Text = tostring(selected)
            end
            RenderOptions()
        end
    }
end

end

modules["components/keybind"] = function()
-- src/components/keybind.lua
local Theme = custom_require("core/theme")
local Utils = custom_require("core/utils")
local UIS = game:GetService("UserInputService")

return function(Tab, name, defaultKey, callback)
    local boundKey = defaultKey or Enum.KeyCode.RightShift
    callback = callback or function() end
    
    local isBinding = false
    
    -- Main Keybind Frame (Glass)
    local Frame = Instance.new("Frame", Tab.Frame)
    Frame.Size = UDim2.new(1, 0, 0, 38)
    Frame.BackgroundColor3 = Theme.Glass
    Frame.BackgroundTransparency = 0.75
    Frame.BorderSizePixel = 0
    Frame.ZIndex = 2
    Utils.Corner(Frame, 8)
    Utils.GlassBorder(Frame, 0.8)

    -- Label
    local Label = Instance.new("TextLabel", Frame)
    Label.Size = UDim2.new(1, -120, 1, 0)
    Label.Position = UDim2.new(0, 14, 0, 0)
    Label.BackgroundTransparency = 1
    Label.Text = name
    Label.TextColor3 = Theme.Text
    Label.TextSize = 13
    Label.Font = Theme.Font
    Label.TextXAlignment = Enum.TextXAlignment.Left
    Label.ZIndex = 3

    -- Keybind Button
    local Btn = Instance.new("TextButton", Frame)
    Btn.Size = UDim2.new(0, 90, 0, 24)
    Btn.Position = UDim2.new(1, -100, 0.5, -12)
    Btn.BackgroundColor3 = Theme.GlassLight
    Btn.BackgroundTransparency = 0.7
    Btn.Text = boundKey and tostring(boundKey.Name or boundKey) or "None"
    Btn.TextColor3 = Theme.Accent
    Btn.TextSize = 12
    Btn.Font = Theme.FontBold
    Btn.AutoButtonColor = false
    Btn.ZIndex = 3
    Utils.Corner(Btn, 6)
    Utils.GlassBorder(Btn, 0.6)

    -- Format display text for mouse and keys
    local function GetKeyName(input)
        if not input then return "None" end
        if input == Enum.KeyCode.Unknown then return "None" end
        
        local nameStr = tostring(input.Name or input)
        -- Clean up Roblox names
        nameStr = nameStr:gsub("MouseButton", "MB")
        return nameStr
    end

    local function UpdateButton()
        Btn.Text = isBinding and "..." or GetKeyName(boundKey)
        Utils.Tween(Btn, 0.15, {
            TextColor3 = isBinding and Theme.Text or Theme.Accent,
            BackgroundColor3 = isBinding and Theme.Accent or Theme.GlassLight,
            BackgroundTransparency = isBinding and 0.4 or 0.7
        })
    end

    -- Global Bind Listener
    local inputConnection
    inputConnection = UIS.InputBegan:Connect(function(input, processed)
        if processed then return end
        
        -- Trigger bind callback
        if boundKey then
            if input.KeyCode == boundKey or input.UserInputType == boundKey then
                task.spawn(callback, boundKey)
            end
        end
    end)

    -- Bind Capture Logic
    Btn.MouseButton1Click:Connect(function()
        if isBinding then return end
        isBinding = true
        UpdateButton()
        
        local tempConnection
        tempConnection = UIS.InputBegan:Connect(function(input, processed)
            -- Don't capture text inputs
            if UIS:GetFocusedTextBox() then return end
            
            local key = nil
            if input.KeyCode ~= Enum.KeyCode.Unknown then
                key = input.KeyCode
            elseif input.UserInputType == Enum.UserInputType.MouseButton1 or 
                   input.UserInputType == Enum.UserInputType.MouseButton2 or 
                   input.UserInputType == Enum.UserInputType.MouseButton3 then
                key = input.UserInputType
            end
            
            -- Cancel/Clear if escape or backspace
            if key == Enum.KeyCode.Escape or key == Enum.KeyCode.Backspace then
                boundKey = nil
                isBinding = false
                tempConnection:Disconnect()
                UpdateButton()
                return
            end
            
            if key then
                boundKey = key
                isBinding = false
                tempConnection:Disconnect()
                UpdateButton()
            end
        end)
    end)

    -- Hover effects
    Frame.MouseEnter:Connect(function()
        Utils.Tween(Frame, 0.15, {BackgroundTransparency = 0.65})
    end)
    Frame.MouseLeave:Connect(function()
        Utils.Tween(Frame, 0.15, {BackgroundTransparency = 0.75})
    end)

    table.insert(Tab.Elements, { Frame = Frame, Name = name })

    -- Clean up connections on destroy
    Frame.Destroying:Connect(function()
        if inputConnection then inputConnection:Disconnect() end
    end)

    return {
        Set = function(newKey)
            boundKey = newKey
            UpdateButton()
        end,
        Get = function() return boundKey end
    }
end

end

