modules["core/utils"] = function()
-- src/core/utils.lua
local TweenService = game:GetService("TweenService")
local Theme = custom_require("theme")

local Utils = {}

-- Enhanced Tween with theme defaults
function Utils.Tween(obj, time, props)
    time = time or Theme.TweenTime
    local info = TweenInfo.new(time, Theme.EasingStyle, Theme.EasingDirection)
    local tween = TweenService:Create(obj, info, props)
    tween:Play()
    return tween
end

-- Create rounded corners
function Utils.Corner(obj, radius)
    local c = Instance.new("UICorner", obj)
    c.CornerRadius = UDim.new(0, radius or 8)
    return c
end

-- Create glass border with gradient for realistic glass refraction
function Utils.GlassBorder(obj, thickness)
    thickness = thickness or 1
    
    local stroke = Instance.new("UIStroke", obj)
    stroke.Color = Color3.fromRGB(255, 255, 255)
    stroke.Thickness = thickness
    stroke.Transparency = 0.5
    
    local gradient = Instance.new("UIGradient", stroke)
    gradient.Color = ColorSequence.new({
        ColorSequenceKeypoint.new(0, Color3.fromRGB(255, 255, 255)),
        ColorSequenceKeypoint.new(0.4, Theme.GlassBorder),
        ColorSequenceKeypoint.new(1, Color3.fromRGB(30, 30, 45))
    })
    gradient.Transparency = NumberSequence.new({
        NumberSequenceKeypoint.new(0, 0.4),  -- Glowing top edge highlight
        NumberSequenceKeypoint.new(0.4, 0.7), -- Glass border default
        NumberSequenceKeypoint.new(1, 0.9)   -- Darker bottom edge shadow
    })
    gradient.Rotation = 45
    
    return stroke
end

-- Create glass effect (layered transparency + gradient)
function Utils.CreateGlass(parent, size, position, transparency)
    transparency = transparency or Theme.GlassTransparency
    
    -- Base glass layer
    local glass = Instance.new("Frame", parent)
    glass.Size = size or UDim2.new(1, 0, 1, 0)
    glass.Position = position or UDim2.new(0, 0, 0, 0)
    glass.BackgroundColor3 = Theme.Glass
    glass.BackgroundTransparency = transparency
    glass.BorderSizePixel = 0
    glass.ZIndex = 1
    
    -- Gradient overlay for depth
    local gradient = Instance.new("UIGradient", glass)
    gradient.Color = ColorSequence.new({
        ColorSequenceKeypoint.new(0, Color3.fromRGB(255, 255, 255)),
        ColorSequenceKeypoint.new(0.5, Color3.fromRGB(220, 220, 240)),
        ColorSequenceKeypoint.new(1, Color3.fromRGB(150, 150, 180))
    })
    gradient.Transparency = NumberSequence.new({
        NumberSequenceKeypoint.new(0, 0.92),
        NumberSequenceKeypoint.new(0.5, 0.96),
        NumberSequenceKeypoint.new(1, 0.88)
    })
    gradient.Rotation = 45
    
    Utils.Corner(glass, 8)
    Utils.GlassBorder(glass, 1)
    
    return glass
end

-- Create soft shadow
function Utils.CreateShadow(parent, size, offset, transparency)
    local shadow = Instance.new("Frame", parent)
    shadow.Size = size or UDim2.new(1, 10, 1, 10)
    shadow.Position = offset or UDim2.new(0, -5, 0, -5)
    shadow.BackgroundColor3 = Theme.ShadowColor
    shadow.BackgroundTransparency = transparency or Theme.ShadowTransparency
    shadow.ZIndex = parent.ZIndex - 1
    Utils.Corner(shadow, 12)
    
    -- Blur effect
    local blur = Instance.new("ImageLabel", shadow)
    blur.Size = UDim2.new(1, 0, 1, 0)
    blur.BackgroundTransparency = 1
    blur.Image = "rbxassetid://5554236805" -- Soft blur texture
    blur.ImageColor3 = Theme.ShadowColor
    blur.ImageTransparency = 0.65
    blur.ScaleType = Enum.ScaleType.Slice
    blur.SliceCenter = Rect.new(23, 23, 277, 277)
    
    return shadow
end

-- Create glowing background blob for liquid neon effect
function Utils.CreateGlowBlob(parent, color, size, position)
    local blob = Instance.new("ImageLabel", parent)
    blob.Size = size or UDim2.new(0, 250, 0, 250)
    blob.Position = position or UDim2.new(0, 0, 0, 0)
    blob.BackgroundTransparency = 1
    blob.Image = "rbxassetid://5554236805" -- Soft blur texture
    blob.ImageColor3 = color
    blob.ImageTransparency = 0.91 -- Very soft and subtle
    blob.ZIndex = 0
    return blob
end

-- Make frame draggable with smooth physics
function Utils.MakeDraggable(frame, dragObj)
    local UIS = game:GetService("UserInputService")
    local dragging, dragStart, startPos
    local dragConnection, endConnection

    dragObj.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
            dragging = true
            dragStart = input.Position
            startPos = frame.Position
            
            -- Lift effect (scale up + glow highlight)
            Utils.Tween(frame, 0.2, {
                Size = UDim2.new(
                    frame.Size.X.Scale, frame.Size.X.Offset + 4,
                    frame.Size.Y.Scale, frame.Size.Y.Offset + 4
                )
            })
            
            dragConnection = UIS.InputChanged:Connect(function(moveInput)
                if moveInput.UserInputType == Enum.UserInputType.MouseMovement or moveInput.UserInputType == Enum.UserInputType.Touch then
                    local delta = moveInput.Position - dragStart
                    frame.Position = UDim2.new(
                        startPos.X.Scale, startPos.X.Offset + delta.X,
                        startPos.Y.Scale, startPos.Y.Offset + delta.Y
                    )
                end
            end)
            
            endConnection = UIS.InputEnded:Connect(function(endInput)
                if endInput.UserInputType == Enum.UserInputType.MouseButton1 or endInput.UserInputType == Enum.UserInputType.Touch then
                    dragging = false
                    if dragConnection then
                        dragConnection:Disconnect()
                        dragConnection = nil
                    end
                    if endConnection then
                        endConnection:Disconnect()
                        endConnection = nil
                    end
                    Utils.Tween(frame, 0.2, {
                        Size = UDim2.new(
                            frame.Size.X.Scale, frame.Size.X.Offset - 4,
                            frame.Size.Y.Scale, frame.Size.Y.Offset - 4
                        )
                    })
                end
            end)
        end
    end)
end

-- Create hover effect
function Utils.HoverEffect(obj, hoverColor, normalColor)
    hoverColor = hoverColor or Theme.GlassLight
    normalColor = normalColor or Theme.Glass
    
    obj.MouseEnter:Connect(function()
        Utils.Tween(obj, 0.15, {BackgroundColor3 = hoverColor, BackgroundTransparency = 0.6})
    end)
    
    obj.MouseLeave:Connect(function()
        Utils.Tween(obj, 0.15, {BackgroundColor3 = normalColor, BackgroundTransparency = 0.75})
    end)
end

-- Style custom scrollbar
function Utils.StyleScroll(scroll)
    scroll.ScrollBarThickness = 3
    scroll.ScrollBarImageColor3 = Theme.Accent
    scroll.ScrollBarImageTransparency = 0.5
    scroll.BorderSizePixel = 0
end

return Utils
end

modules["core/window"] = function()
-- src/core/window.lua
local Theme = custom_require("theme")
local Utils = custom_require("utils")
local Notification = custom_require("notification")
local Icons = custom_require("icons")
local UIS = game:GetService("UserInputService")

local WindowModule = {}

function WindowModule.new(config)
    local Window = { 
        Tabs = {}, 
        ActiveTab = nil,
        ActiveView = nil, -- Tracks either the active tab or active sub-tab for search filter
        ToggleKey = config.ToggleKey or Enum.KeyCode.RightShift,
        Visible = true
    }
    config = config or {}

    -- GUI Setup
    local ScreenGui = Instance.new("ScreenGui")
    ScreenGui.Name = "QwenUI_" .. math.random(10000, 99999)
    ScreenGui.ResetOnSpawn = false
    ScreenGui.ZIndexBehavior = Enum.ZIndexBehavior.Sibling
    
    -- Set ScreenGui Parent safely to avoid anti-cheat SEH crashes on broken executors
    local targetParent = config.Parent
    
    if not targetParent then
        print("[QwenUI] No config.Parent provided, searching for PlayerGui...")
        targetParent = game:GetService("Players").LocalPlayer:WaitForChild("PlayerGui", 5)
        if not targetParent then
            warn("[QwenUI] PlayerGui not found within 5 seconds! Defaulting to CoreGui to avoid silent freeze.")
            -- If we can't find PlayerGui, the script would just freeze silently.
            -- We fallback to CoreGui as a last resort, but wrapped safely.
            pcall(function() targetParent = game:GetService("CoreGui") end)
        end
    end
    print("[QwenUI] ScreenGui Parent set to:", tostring(targetParent))
    
    ScreenGui.Parent = targetParent

    -- Shadow Layer
    local Shadow = Instance.new("Frame", ScreenGui)
    Shadow.Size = config.Size or UDim2.new(0, 620, 0, 460)
    Shadow.Position = UDim2.new(0.5, -310, 0.5, -230)
    Shadow.BackgroundTransparency = 1
    Utils.CreateShadow(Shadow, UDim2.new(1, 20, 1, 20), UDim2.new(0, -10, 0, -10), 0.65)

    -- Main Frame (Obsidian Dark Glass)
    local Main = Instance.new("Frame", ScreenGui)
    Main.Size = config.Size or UDim2.new(0, 620, 0, 460)
    Main.Position = UDim2.new(0.5, -310, 0.5, -230)
    Main.BackgroundColor3 = Theme.Background
    Main.BackgroundTransparency = 0.12
    Main.BorderSizePixel = 0
    Utils.Corner(Main, 12)
    Utils.GlassBorder(Main, 1.5)
    Utils.MakeDraggable(Main, Main)

    -- Liquid Neon Background Blobs
    local Blob1 = Utils.CreateGlowBlob(Main, Theme.Accent, UDim2.new(0, 260, 0, 260), UDim2.new(-0.2, 0, -0.2, 0))
    local Blob2 = Utils.CreateGlowBlob(Main, Color3.fromRGB(180, 0, 255), UDim2.new(0, 300, 0, 300), UDim2.new(0.6, 0, 0.5, 0))
    
    -- Animate Neon Blobs (Liquid Flow)
    task.spawn(function()
        local startTime = os.clock()
        while task.wait(0.04) do
            if not Main or not Main.Parent then break end
            local t = os.clock() - startTime
            local x1 = -0.15 + 0.12 * math.sin(t * 0.4)
            local y1 = -0.15 + 0.12 * math.cos(t * 0.3)
            local x2 = 0.55 + 0.12 * math.cos(t * 0.25)
            local y2 = 0.45 + 0.12 * math.sin(t * 0.35)
            Blob1.Position = UDim2.new(x1, 0, y1, 0)
            Blob2.Position = UDim2.new(x2, 0, y2, 0)
        end
    end)

    -- Glass overlay for frosted effect
    local GlassOverlay = Instance.new("Frame", Main)
    GlassOverlay.Size = UDim2.new(1, 0, 1, 0)
    GlassOverlay.BackgroundColor3 = Theme.Glass
    GlassOverlay.BackgroundTransparency = Theme.GlassTransparency
    GlassOverlay.ZIndex = 1
    Utils.Corner(GlassOverlay, 12)

    -- Title Bar
    local TitleBar = Instance.new("Frame", Main)
    TitleBar.Size = UDim2.new(1, 0, 0, 42)
    TitleBar.BackgroundColor3 = Theme.GlassLight
    TitleBar.BackgroundTransparency = 0.65
    TitleBar.BorderSizePixel = 0
    TitleBar.ZIndex = 3
    Utils.Corner(TitleBar, 12)
    -- Hide bottom rounded corners of title bar
    local TitleBarBottomCut = Instance.new("Frame", TitleBar)
    TitleBarBottomCut.Size = UDim2.new(1, 0, 0, 6)
    TitleBarBottomCut.Position = UDim2.new(0, 0, 1, -6)
    TitleBarBottomCut.BackgroundColor3 = Theme.GlassLight
    TitleBarBottomCut.BackgroundTransparency = 0.65
    TitleBarBottomCut.BorderSizePixel = 0
    TitleBarBottomCut.ZIndex = 3

    -- Title Text
    local Title = Instance.new("TextLabel", TitleBar)
    Title.Size = UDim2.new(1, -220, 1, 0)
    Title.Position = UDim2.new(0, 20, 0, 0)
    Title.BackgroundTransparency = 1
    Title.Text = config.Name or "QwenUILib"
    Title.TextColor3 = Theme.Text
    Title.TextSize = 15
    Title.Font = Theme.FontBold
    Title.TextXAlignment = Enum.TextXAlignment.Left
    Title.ZIndex = 4

    -- Search Box (Glass Effect)
    local SearchContainer = Instance.new("Frame", TitleBar)
    SearchContainer.Size = UDim2.new(0, 180, 0, 28)
    SearchContainer.Position = UDim2.new(1, -195, 0.5, -14)
    SearchContainer.BackgroundColor3 = Theme.Glass
    SearchContainer.BackgroundTransparency = 0.75
    SearchContainer.ZIndex = 4
    Utils.Corner(SearchContainer, 6)
    Utils.GlassBorder(SearchContainer, 0.8)

    local SearchIcon = Instance.new("TextLabel", SearchContainer)
    SearchIcon.Size = UDim2.new(0, 24, 1, 0)
    SearchIcon.Position = UDim2.new(0, 8, 0, 0)
    SearchIcon.BackgroundTransparency = 1
    SearchIcon.Text = "🔍"
    SearchIcon.TextSize = 12
    SearchIcon.ZIndex = 5

    local SearchBox = Instance.new("TextBox", SearchContainer)
    SearchBox.Size = UDim2.new(1, -38, 1, 0)
    SearchBox.Position = UDim2.new(0, 32, 0, 0)
    SearchBox.BackgroundTransparency = 1
    SearchBox.Text = ""
    SearchBox.PlaceholderText = "Search elements..."
    SearchBox.PlaceholderColor3 = Theme.Muted
    SearchBox.TextColor3 = Theme.Text
    SearchBox.TextSize = 12
    SearchBox.Font = Theme.Font
    SearchBox.ClearTextOnFocus = false
    SearchBox.ZIndex = 5

    -- Sidebar (Scrollable Tab Container)
    local Sidebar = Instance.new("ScrollingFrame", Main)
